/* ---------- helpers ---------- */

function readLocal(key, fallback) {
  try {
    const raw = window.localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch {
    return fallback;
  }
}
function writeLocal(key, value) {
  try { window.localStorage.setItem(key, JSON.stringify(value)); } catch {}
}

function useGuestBook() {
  const [guests, setGuests] = useState(() => readLocal("mirella:guests", GUEST_SEED));
  const save = (next) => { setGuests(next); writeLocal("mirella:guests", next); };
  return [guests, save];
}

function useGifts() {
  const [gifts, setGifts] = useState(() => readLocal("mirella:gifts", GIFT_SEED));
  const save = (next) => { setGifts(next); writeLocal("mirella:gifts", next); };
  return [gifts, save];
}

function useMemories() {
  const [items, setItems] = useState(() => readLocal("mirella:memorias", []));
  const add = (entry) => {
    const next = [entry, ...items];
    setItems(next);
    writeLocal("mirella:memorias", next);
  };
  return [items, add];
}

