/* ---------- Login screen ---------- */

function LoginScreen({ guests, onEnter }) {
  const [code, setCode] = useState("");
  const [error, setError] = useState("");
  const [showCodes, setShowCodes] = useState(false);

  const submit = (e) => {
    e.preventDefault();
    const clean = code.trim().toUpperCase();
    if (guests && guests[clean]) {
      setError("");
      onEnter(clean);
    } else {
      setError("Não encontramos esse código. Confira o convite que você recebeu.");
    }
  };

  return (
    <div className="min-h-screen bg-[#152018] flex items-center justify-center px-6 py-16 relative overflow-hidden">
      <div
        className="absolute inset-0 bg-cover bg-center"
        style={{ backgroundImage: `url(${PHOTOS[1].src})` }}
      />
      <div className="absolute inset-0 bg-[#152018]/85" />
      <div
        className="absolute inset-0 opacity-[0.07] pointer-events-none"
        style={{
          backgroundImage:
            "radial-gradient(circle at 20% 20%, #C7A54A 0, transparent 2px), radial-gradient(circle at 80% 60%, #C7A54A 0, transparent 2px), radial-gradient(circle at 50% 90%, #C7A54A 0, transparent 2px)",
          backgroundSize: "140px 140px",
        }}
      />
      <div className="w-full max-w-sm relative">
        <div className="text-center mb-10">
          <div className="text-[11px] tracking-[0.35em] uppercase text-[#8FA294] mb-2">Você está convidado(a) para</div>
          <div className="text-5xl text-[#F3EEE2]" style={{ fontFamily: "Georgia, serif" }}>15 anos de <span className="text-[#C7A54A]">Myrella</span></div>
          <div className="text-[#8FA294] text-sm mt-2 tracking-wide">21 de agosto de 2026 · 19h · [local]</div>
        </div>

        <form onSubmit={submit} className="bg-[#1E2E24] border border-[#33463A] rounded-lg p-7">
          <label className="flex items-center gap-2 text-[#F3EEE2] text-sm mb-3">
            <Lock size={15} className="text-[#C7A54A]" />
            Código do seu convite
          </label>
          <input
            value={code}
            onChange={(e) => { setCode(e.target.value); setError(""); }}
            placeholder="Ex: MIREL-014"
            className="w-full bg-[#152018] border border-[#3C4F42] rounded-md px-4 py-3 text-[#F3EEE2] placeholder:text-[#5C6E62] tracking-widest uppercase focus:outline-none focus:ring-2 focus:ring-[#C7A54A]"
          />
          {error && <div className="text-[#D98A7E] text-xs mt-2">{error}</div>}
          <button
            type="submit"
            className="mt-5 w-full bg-[#C7A54A] hover:bg-[#D4B360] text-[#1B2A22] font-medium rounded-md py-3 transition-colors flex items-center justify-center gap-2"
          >
            Entrar <ChevronRight size={16} />
          </button>
        </form>

        <button
          onClick={() => setShowCodes((s) => !s)}
          className="mt-4 text-xs text-[#6E8377] hover:text-[#8FA294] w-full text-center underline-offset-2 hover:underline"
        >
          {showCodes ? "ocultar" : "não recebi um código — código de teste para demonstração"}
        </button>
        {showCodes && (
          <div className="mt-2 text-center text-xs text-[#8FA294] space-y-0.5">
            {Object.keys(GUEST_SEED).map((c) => <div key={c}>{c}</div>)}
          </div>
        )}
      </div>
    </div>
  );
}

