function PaymentModal({ gift, onClose, onConfirm }) {
  const [method, setMethod] = useState(null);
  const [done, setDone] = useState(false);
  const [card, setCard] = useState({ numero: "", nome: "", validade: "" });

  const finish = () => {
    setDone(true);
    setTimeout(() => onConfirm(), 1100);
  };

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center p-4 z-50">
      <div className="bg-[#1E2E24] border border-[#3C4F42] rounded-lg w-full max-w-sm p-6 relative">
        <button onClick={onClose} className="absolute top-4 right-4 text-[#8FA294] hover:text-[#F3EEE2]"><X size={18} /></button>

        {done ? (
          <div className="text-center py-8">
            <Check className="mx-auto text-[#8FBF9F] mb-3" size={32} />
            <div className="text-[#F3EEE2]" style={{ fontFamily: "Georgia, serif" }}>Presente confirmado!</div>
            <div className="text-[#8FA294] text-sm mt-1">Obrigado por fazer parte disso com a gente.</div>
          </div>
        ) : !method ? (
          <>
            <div className="text-[#F3EEE2] mb-1" style={{ fontFamily: "Georgia, serif" }}>{gift.nome}</div>
            <div className="text-[#C7A54A] text-lg mb-5">R$ {gift.valor.toFixed(2)}</div>
            <div className="text-[#8FA294] text-xs mb-3 uppercase tracking-widest">Como você prefere presentear</div>
            <button onClick={() => setMethod("pix")} className="w-full flex items-center gap-3 bg-[#152018] border border-[#3C4F42] rounded-md px-4 py-3 mb-2 text-[#F3EEE2] hover:border-[#C7A54A]">
              <QrCode size={18} className="text-[#C7A54A]" /> Pagar com Pix
            </button>
            <button onClick={() => setMethod("cartao")} className="w-full flex items-center gap-3 bg-[#152018] border border-[#3C4F42] rounded-md px-4 py-3 text-[#F3EEE2] hover:border-[#C7A54A]">
              <CreditCard size={18} className="text-[#C7A54A]" /> Pagar com cartão
            </button>
            <div className="text-[10px] text-[#6E8377] mt-4 text-center">O valor vai direto para a conta da família, com segurança.</div>
          </>
        ) : method === "pix" ? (
          <>
            <div className="text-[#F3EEE2] mb-4" style={{ fontFamily: "Georgia, serif" }}>Pague com Pix</div>
            <div className="w-40 h-40 bg-white mx-auto rounded-md mb-4 flex items-center justify-center">
              <QrCode size={90} className="text-[#152018]" />
            </div>
            <div className="text-[#8FA294] text-xs text-center mb-4">Escaneie o QR code no app do seu banco — R$ {gift.valor.toFixed(2)}</div>
            <button onClick={finish} className="w-full bg-[#C7A54A] hover:bg-[#D4B360] text-[#1B2A22] font-medium rounded-md py-3">Já paguei</button>
          </>
        ) : (
          <>
            <div className="text-[#F3EEE2] mb-4" style={{ fontFamily: "Georgia, serif" }}>Pagar com cartão</div>
            <input value={card.numero} onChange={(e) => setCard({ ...card, numero: e.target.value })} placeholder="Número do cartão" className="w-full bg-[#152018] border border-[#3C4F42] rounded-md px-3 py-2.5 text-[#F3EEE2] mb-2 text-sm placeholder:text-[#5C6E62]" />
            <input value={card.nome} onChange={(e) => setCard({ ...card, nome: e.target.value })} placeholder="Nome impresso no cartão" className="w-full bg-[#152018] border border-[#3C4F42] rounded-md px-3 py-2.5 text-[#F3EEE2] mb-2 text-sm placeholder:text-[#5C6E62]" />
            <input value={card.validade} onChange={(e) => setCard({ ...card, validade: e.target.value })} placeholder="Validade MM/AA" className="w-full bg-[#152018] border border-[#3C4F42] rounded-md px-3 py-2.5 text-[#F3EEE2] mb-4 text-sm placeholder:text-[#5C6E62]" />
            <button onClick={finish} className="w-full bg-[#C7A54A] hover:bg-[#D4B360] text-[#1B2A22] font-medium rounded-md py-3">Confirmar R$ {gift.valor.toFixed(2)}</button>
            <div className="text-[10px] text-[#6E8377] mt-3 text-center">Ambiente de demonstração — nenhuma cobrança real é feita aqui.</div>
          </>
        )}
      </div>
    </div>
  );
}

function Presentes({ gifts, saveGifts, user }) {
  const [active, setActive] = useState(null);

  const reserve = async () => {
    const next = gifts.map((g) => (g.id === active.id ? { ...g, reservadoPor: user.nome } : g));
    await saveGifts(next);
    setActive(null);
  };

  if (!gifts) return null;

  return (
    <div>
      <Eyebrow>Lista de presentes</Eyebrow>
      <SectionTitle>Presentear</SectionTitle>
      <p className="text-[#8FA294] text-sm mb-6 max-w-md">
        Preparamos essa lista com carinho. Os presentes só podem ser dados por aqui — assim garantimos que
        chega certinho para a gente.
      </p>
      <div className="grid sm:grid-cols-2 gap-4">
        {gifts.map((g) => (
          <div key={g.id} className="bg-[#1E2E24] border border-[#33463A] rounded-md p-5 flex flex-col">
            <div className="text-[#F3EEE2]" style={{ fontFamily: "Georgia, serif" }}>{g.nome}</div>
            <div className="text-[#8FA294] text-sm mt-1 flex-1">{g.desc}</div>
            <div className="text-[#C7A54A] mt-3">R$ {g.valor.toFixed(2)}</div>
            {g.reservadoPor ? (
              <div className="mt-3 text-xs text-[#8FBF9F] flex items-center gap-1"><CheckCircle2 size={13} /> Já presenteado por {g.reservadoPor}</div>
            ) : (
              <button onClick={() => setActive(g)} className="mt-3 bg-[#C7A54A]/15 hover:bg-[#C7A54A]/25 text-[#C7A54A] text-sm rounded-md py-2 transition-colors">
                Presentear
              </button>
            )}
          </div>
        ))}
      </div>
      {active && <PaymentModal gift={active} onClose={() => setActive(null)} onConfirm={reserve} />}
    </div>
  );
}

function Memorias({ user }) {
  const [items, addItem] = useMemories();
  const [texto, setTexto] = useState("");
  const [preview, setPreview] = useState(null);
  const fileRef = useRef(null);

  const onFile = (e) => {
    const f = e.target.files?.[0];
    if (f) setPreview(URL.createObjectURL(f));
  };

  const send = async () => {
    if (!texto.trim() && !preview) return;
    await addItem({ autor: user.nome, texto, temFoto: !!preview, ts: Date.now() });
    setTexto("");
    setPreview(null);
    if (fileRef.current) fileRef.current.value = "";
  };

  return (
    <div>
      <Eyebrow>Álbum coletivo</Eyebrow>
      <SectionTitle>Fotos e lembranças</SectionTitle>
      <p className="text-[#8FA294] text-sm mb-6 max-w-md">
        Tem uma foto antiga, um vídeo da festa ou uma história pra contar? Deixa aqui — algumas podem entrar
        na cerimônia.
      </p>

      <div className="bg-[#1E2E24] border border-[#33463A] rounded-md p-5 max-w-lg mb-8">
        <textarea
          value={texto}
          onChange={(e) => setTexto(e.target.value)}
          placeholder="Conte uma lembrança, uma história ou uma mensagem..."
          rows={3}
          className="w-full bg-[#152018] border border-[#3C4F42] rounded-md px-3 py-2 text-sm text-[#F3EEE2] placeholder:text-[#5C6E62] focus:outline-none focus:ring-2 focus:ring-[#C7A54A] resize-none"
        />
        <div className="flex items-center justify-between mt-3">
          <label className="flex items-center gap-2 text-xs text-[#8FA294] cursor-pointer hover:text-[#C7A54A]">
            <Upload size={14} />
            {preview ? "Foto anexada" : "Anexar foto ou vídeo"}
            <input ref={fileRef} type="file" accept="image/*,video/*" className="hidden" onChange={onFile} />
          </label>
          <button onClick={send} className="bg-[#C7A54A] hover:bg-[#D4B360] text-[#1B2A22] text-sm font-medium rounded-md px-4 py-2">
            Enviar
          </button>
        </div>
        {preview && <img src={preview} alt="Prévia" className="mt-3 rounded-md max-h-40 object-cover" />}
      </div>

      <div className="space-y-3 max-w-lg">
        {items.length === 0 && <div className="text-[#6E8377] text-sm">Nenhuma lembrança enviada ainda — seja a primeira pessoa.</div>}
        {items.map((it, i) => (
          <div key={i} className="border border-[#33463A] rounded-md px-4 py-3 bg-[#1E2E24]">
            <div className="text-[#C7A54A] text-xs">{it.autor}</div>
            <div className="text-[#B9C5BC] text-sm mt-1">{it.texto}{it.temFoto && " 📷"}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

